class Solution {
public:
    int largestInteger(int num) {
        string s = to_string(num);
        vector<int> odd, even;
        for (char c : s) {
            if ((c - '0') % 2 == 0) even.push_back(c - '0');
            else odd.push_back(c - '0');
        }
        sort(odd.rbegin(), odd.rend());
        sort(even.rbegin(), even.rend());
        int o = 0, e = 0;
        for (char c : s) {
            if ((c - '0') % 2 == 0) {
                s[c - '0' + '0' - '0'] = even[e] + '0';
                e++;
            } else {
                s[c - '0' + '0' - '0'] = odd[o] + '0';
                o++;
            }
        }
        return stoi(s);
    }
};
